import Fondo from "../Cabañas/Foto9.jpg"

const Actividades = () => {
    return (
        <section className="h-screen snap-start flex items-center justify-center" style={{
            backgroundImage: `url('${Fondo}')`,
            backgroundAttachment: "fixed",
            backgroundSize: "cover",
            backgroundPosition: "center",
        }}
        >
            <div className="absolute inset-0 bg-black/50">
                <div className="relative z-10 text-center text-white p-6 rounded-lg">
                    <h2 className="text-4xl font-playfair mb-4">Todo lo que podés disfrutar en Alta Gracia</h2>
                </div>
                <div className="relative z-10 m-auto">
                    <div className="bg-white rounded-lg p-8 max-w-4xl mx-auto text-left text-gray-800 shadow-lg">

                    </div>
                </div>
            </div>


        </section>
    );
}
export default Actividades;
